// Some portions generated by Co-Pilot
import { fetchFeatureReleases, type ReleaseType } from "@/services/adoptiumApi";
import type { Release } from "@/types/temurin";

export interface ReturnedReleases {
  releases: Release[];
  pagecount: number;
}

export async function getAssetsForVersion(
  version: number,
  releaseType: ReleaseType,
  numBuilds: number,
  buildDate: Date,
  page: number,
): Promise<ReturnedReleases | null> {
  const params: Record<string, string> = {};
  params.page = page.toString();
  if (numBuilds) params.page_size = numBuilds.toString();
  if (buildDate) {
    const formattedDate =
      buildDate instanceof Date && !isNaN(buildDate.getTime())
        ? `${buildDate.getFullYear()}-${String(buildDate.getMonth() + 1).padStart(2, "0")}-${String(buildDate.getDate()).padStart(2, "0")}`
        : "";
    if (formattedDate) params.before = formattedDate;
  }
  if (releaseType === "ga") params.show_page_count = "true";

  let releases: Release[] = [];
  let pagecount = 0;

  await fetchFeatureReleases(version, releaseType, params)
    .then(({ data, pagecount: pc }) => {
      releases = data as unknown as Release[];
      pagecount = pc;
    })
    .catch(() => {
      pagecount = 0;
      releases = [];
    });

  // Filter binaries to only include relevant image types
  const allowedTypes =
    releaseType === "ga"
      ? ["JDK", "JRE", "INSTALLER"]
      : ["JDK", "JRE", "INSTALLER", "DEBUGIMAGE"];

  releases = releases.map((release) => ({
    ...release,
    binaries: (release.binaries ?? []).filter((binary) =>
      allowedTypes.includes((binary.image_type ?? "").toUpperCase()),
    ),
  }));

  return { releases, pagecount };
}

// Re-export type alias for the nightly table component
export type { Release as TemurinRelease };
